"use client";

import { useAuth } from "@/context/AuthContext";
import { useEffect, useState } from "react";
import { getRequisitions } from "@/lib/requisitions";
import { getSpendAnalytics, DashboardEvent } from "@/lib/analytics";
import { SpendBarChart, BudgetDonutChart } from "@/components/charts/SimpleCharts";
import { formatCurrency } from "@/lib/currencies";
import Link from "next/link";
import CustomSelect from "@/components/ui/CustomSelect";

export default function Dashboard() {
    const { user } = useAuth();
    const [timeRange, setTimeRange] = useState("Last 6 Months");
    const [stats, setStats] = useState({
        pendingCount: 0,
        activeCount: 0,
        totalSpend: 0,
        savings: 0,
        avgApprovalDays: 0,
        monthlyData: [] as any[],
        activityFeed: [] as DashboardEvent[]
    });
    const [loading, setLoading] = useState(true);

    const loadData = async () => {
        setLoading(true);
        const [reqs, analytics] = await Promise.all([
            getRequisitions(),
            getSpendAnalytics()
        ]);

        const pending = reqs.filter(r => r.status === 'PENDING').length;

        // Mocking monthly data for visualization
        const mockMonthly = [
            { label: 'Jan', value: 12000 },
            { label: 'Feb', value: 19500 },
            { label: 'Mar', value: 15000 },
            { label: 'Apr', value: analytics.totalSpend || 28000 },
            { label: 'May', value: 0 },
            { label: 'Jun', value: 0 },
        ];

        setStats({
            pendingCount: pending,
            activeCount: reqs.length,
            totalSpend: analytics.totalSpend,
            savings: analytics.savings,
            avgApprovalDays: analytics.avgApprovalDays,
            monthlyData: mockMonthly,
            activityFeed: analytics.activityFeed
        });
        setLoading(false);
    };

    useEffect(() => {
        loadData();
    }, []);

    const quickActions = [
        { name: "New Request", href: "/dashboard/requisitions/new", icon: "📝", color: "var(--accent)" },
        { name: "Approve Requests", href: "/dashboard/approvals", icon: "✅", color: "var(--success)" },
        { name: "Check Budget", href: "/dashboard/budgets", icon: "💰", color: "#eab308" },
    ];

    if (loading) return <div style={{ padding: '2rem' }}>Loading Dashboard...</div>;

    return (
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
            {/* Greeting Section */}
            <div style={{ marginBottom: '2.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                <div>
                    <h1 style={{
                        fontSize: '2.5rem',
                        fontWeight: 800,
                        marginBottom: '0.5rem',
                        background: 'linear-gradient(135deg, var(--text-main) 0%, var(--text-secondary) 100%)',
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                        letterSpacing: '-0.03em'
                    }}>
                        Welcome back, {user?.displayName?.split(' ')[0] || 'User'}
                    </h1>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '1.1rem' }}>Here is a summary of your procurement ecosystem.</p>
                </div>
                <div style={{ display: 'flex', gap: '1rem' }}>
                    {quickActions.map(action => (
                        <Link key={action.name} href={action.href} className="btn" style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', backgroundColor: 'white', border: '1px solid var(--border)', fontSize: '0.875rem' }}>
                            <span>{action.icon}</span> {action.name}
                        </Link>
                    ))}
                </div>
            </div>

            {/* Stats Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
                <KPICard
                    title="Total Annual Spend"
                    value={formatCurrency(stats.totalSpend, 'USD')}
                    trend="+12.5%"
                    icon="💸"
                    description="vs previous fiscal year"
                />
                <KPICard
                    title="Realized Savings"
                    value={formatCurrency(stats.savings, 'USD')}
                    trend="5.2%"
                    icon="🛡️"
                    description="negotiated & contract savings"
                />
                <KPICard
                    title="Avg. Approval Time"
                    value={`${stats.avgApprovalDays} Days`}
                    trend="-0.4"
                    icon="⏱️"
                    description="request to order cycle"
                />
                <KPICard
                    title="Pending Actions"
                    value={stats.pendingCount.toString()}
                    urgent={stats.pendingCount > 0}
                    icon="🔔"
                    description="requires immediate attention"
                />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '2rem' }}>

                {/* Left Column: Analytics */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
                    <div className="card">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                            <h2 style={{ fontSize: '1.2rem', fontWeight: 700 }}>Expenditure Trend</h2>
                            <div style={{ width: '180px' }}>
                                <CustomSelect
                                    value={timeRange}
                                    onChange={setTimeRange}
                                    options={[
                                        { label: "Last 6 Months", value: "Last 6 Months" },
                                        { label: "Year to Date", value: "Year to Date" }
                                    ]}
                                />
                            </div>
                        </div>
                        <SpendBarChart data={stats.monthlyData} />
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                        <div className="card">
                            <h3 style={{ fontSize: '1.1rem', fontWeight: 600, marginBottom: '1.5rem' }}>Budget Utilization</h3>
                            <div style={{ display: 'flex', justifyContent: 'center', padding: '1rem 0' }}>
                                <BudgetDonutChart total={100000} used={stats.totalSpend} />
                            </div>
                            <div style={{ marginTop: '1rem', textAlign: 'center', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                                45% of total annual budget remaining
                            </div>
                        </div>
                        <div className="card">
                            <h3 style={{ fontSize: '1.1rem', fontWeight: 600, marginBottom: '1rem' }}>Spend by Category</h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                <CategoryRow label="IT Hardware" value={45} color="var(--primary)" />
                                <CategoryRow label="Office Supplies" value={20} color="var(--accent)" />
                                <CategoryRow label="Software Subs" value={25} color="#8b5cf6" />
                                <CategoryRow label="Marketing Caps" value={10} color="#ec4899" />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right Column: Activity Feed */}
                <div className="card" style={{ display: 'flex', flexDirection: 'column', maxHeight: '1000px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <h2 style={{ fontSize: '1.2rem', fontWeight: 700 }}>Activity Feed</h2>
                        <span style={{ fontSize: '0.75rem', color: 'var(--primary)', fontWeight: 600 }}>LIVE UPDATES</span>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem', overflowY: 'auto' }}>
                        {stats.activityFeed.length === 0 ? (
                            <div style={{ textAlign: 'center', color: 'var(--text-secondary)', padding: '2rem' }}>No recent activity.</div>
                        ) : (
                            stats.activityFeed.map(event => (
                                <ActivityItem key={event.id} event={event} />
                            ))
                        )}
                    </div>

                    <button className="btn-text" style={{ marginTop: 'auto', padding: '1rem 0', color: 'var(--primary)', fontSize: '0.875rem' }}>
                        View System Audit Log →
                    </button>
                </div>
            </div>
        </div>
    );
}

function KPICard({ title, value, trend, icon, description, urgent }: any) {
    return (
        <div className="card" style={{ position: 'relative', overflow: 'hidden', borderLeft: urgent ? '4px solid var(--error)' : '1px solid var(--border)' }}>
            <div style={{ position: 'absolute', top: '-10px', right: '-10px', fontSize: '4rem', opacity: 0.05 }}>{icon}</div>
            <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem', fontWeight: 500 }}>{title}</div>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: '0.5rem' }}>
                <div style={{ fontSize: '1.75rem', fontWeight: 800, color: 'var(--text-main)' }}>{value}</div>
                {trend && <div style={{ fontSize: '0.8rem', color: trend.startsWith('+') ? 'var(--error)' : 'var(--success)', fontWeight: 600 }}>{trend}</div>}
            </div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '0.5rem' }}>{description}</div>
        </div>
    );
}

function CategoryRow({ label, value, color }: { label: string, value: number, color: string }) {
    return (
        <div style={{ fontSize: '0.875rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                <span>{label}</span>
                <span style={{ fontWeight: 600 }}>{value}%</span>
            </div>
            <div style={{ height: '6px', width: '100%', backgroundColor: '#f1f5f9', borderRadius: '3px', overflow: 'hidden' }}>
                <div style={{ height: '100%', width: `${value}%`, backgroundColor: color }}></div>
            </div>
        </div>
    );
}

function ActivityItem({ event }: { event: DashboardEvent }) {
    const getIcon = () => {
        switch (event.type) {
            case 'REQUISITION': return '📄';
            case 'ORDER': return '📦';
            case 'INVOICE': return '🧾';
            default: return '🔔';
        }
    };

    return (
        <div style={{ display: 'flex', gap: '1rem' }}>
            <div style={{
                width: '40px', height: '40px', borderRadius: '12px',
                backgroundColor: '#f8fafc', border: '1px solid #e2e8f0',
                display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.2rem', flexShrink: 0
            }}>
                {getIcon()}
            </div>
            <div style={{ flex: 1 }}>
                <div style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-main)' }}>{event.title}</div>
                <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '0.25rem' }}>{event.description}</div>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem' }}>
                    <span style={{ color: 'var(--text-secondary)' }}>
                        {event.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {event.user}
                    </span>
                    {event.amount && <span style={{ fontWeight: 600 }}>{formatCurrency(event.amount, event.currency)}</span>}
                </div>
            </div>
        </div>
    );
}
