import { db } from "./firebase";
import { ref, push, set, get, child, update, query, orderByChild, equalTo } from "firebase/database";
import { Requisition, RequisitionStatus } from "@/types";
import { getApproverForRequest } from "./approvals";

const COLLECTION_NAME = "requisitions";

export const createRequisition = async (requisition: Omit<Requisition, 'id' | 'createdAt'>) => {
    try {
        // Determine Approver
        const approver = getApproverForRequest(requisition.department, requisition.totalAmount);

        const reqsRef = ref(db, COLLECTION_NAME);
        const newReqRef = push(reqsRef);

        await set(newReqRef, {
            ...requisition,
            id: newReqRef.key,
            createdAt: new Date().toISOString(),
            status: 'PENDING' as RequisitionStatus,
            approverId: approver.uid,
            approverName: approver.name // Optional: Store name for display
        });

        return newReqRef.key;
    } catch (error) {
        console.error("Error creating requisition: ", error);
        throw error;
    }
};

export const getRequisitions = async (): Promise<Requisition[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, COLLECTION_NAME));

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.values(data).map((v: any) => ({
                ...v,
                createdAt: new Date(v.createdAt),
            })) as Requisition[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching requisitions", error);
        return [];
    }
};

export const updateRequisitionStatus = async (reqId: string, status: RequisitionStatus, approverId?: string) => {
    const reqRef = ref(db, `${COLLECTION_NAME}/${reqId}`);
    const updates: any = { status };
    if (approverId) updates.approverId = approverId;

    await update(reqRef, updates);
};
